import{a as e,c as t,i as n,l as r,n as i,o as a,r as o,s,t as c}from"./app-D4aLiheH.js";var l=JSON.parse(`{"path":"/reference/basic-grammar.html","title":"Basic Grammar","lang":"en-US","frontmatter":{"lang":"en-US","title":"Basic Grammar","description":"A reference for Kokanu grammar"},"git":{"updatedTime":1781933736000,"contributors":[{"name":"KSPAtlas","username":"KSPAtlas","email":"kspatlas@disroot.org","commits":6,"url":"https://github.com/KSPAtlas"},{"name":"Dev Bali","username":"","email":"devbali@berkeley.edu","commits":1},{"name":"Geofinnstar","username":"Geofinnstar","email":"127263153+Geofinnstar@users.noreply.github.com","commits":19,"url":"https://github.com/Geofinnstar"}],"changelog":[{"hash":"586a3b8f49d90c77610cd16ceaf5175660241b2e","time":1781933736000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"Update basic-grammar.md"},{"hash":"f9f948331e579579da2a4dec72081ca7cb5fa59f","time":1781933647000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"Update basic-grammar.md"},{"hash":"0aaf5ea6557801089ba07d1656eee8b15bd64527","time":1781933543000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"Update basic-grammar.md"},{"hash":"e940675de516f2c4ca0aeaf29ab05e1172578033","time":1781933491000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"Update basic-grammar.md"},{"hash":"4e02c9d2ea4e301b1dfdfd3859f3d90f447caea0","time":1781933358000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"small"},{"hash":"c63996d86a3584f2ab9a72606698936afbaee88f","time":1781933294000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"small typo"},{"hash":"746a03d4b1f756966673745d8cdc7889cc1190fc","time":1781933149000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"final changes rahh!!!"},{"hash":"89569cb41c50aec4fed58131a8dcd6258266e812","time":1781932666000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"DONE RELATIVE CLAUSES RAHH!!!"},{"hash":"0b03db56282ea0e2faee3eac43d5f859ab47b242","time":1781024392000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"Update basic-grammar.md wip again"},{"hash":"679bc97c6ad55ebfa233b0e3e16eb08369164562","time":1779235869000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"basic-grammar.md update again woohoo"},{"hash":"3d69c32934650cf174e7c721235d94e7763ec2c3","time":1779136339000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"basic-grammar.md update part idk"},{"hash":"a94c28d4a1e3893ad7efdc519b38da85185e9e84","time":1779135326000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"small change"},{"hash":"7e5570666a30b0101c5aaa63257e3e1cb8c90120","time":1778801538000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"basic-grammar.md refactor part 2"},{"hash":"dca136ebe97ae946462dc18add59c2a99ec6327a","time":1778800736000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"basic-grammar.md refactor part 1"},{"hash":"2f51e75a486dbd1c1e28b8a0537a9a8ab3d1714a","time":1772340490000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"fixing formatting mistakes"},{"hash":"8c7593448b7a33cb367567d91d6e83992ee70793","time":1765066015000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"basic-grammar more colour and general changes"},{"hash":"21d3ce30817a3d4f255f8cf7d15bc1d71bd9bd88","time":1765065625000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"Update basic-grammar.md some basic chnges"},{"hash":"041e5ae6ef0e3e074d7b0043a4e6dfe7c57c7c8c","time":1760241540000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"Updated basic-grammar.md misc changes"},{"hash":"f1a7a7ca1ab212d893fee02fef6ce91bce8facee","time":1760240749000,"email":"127263153+Geofinnstar@users.noreply.github.com","author":"Geofinnstar","message":"some fixes to basic-grammar.md"},{"hash":"a9a0c30160185504ac75c8a10396cf5d7380e30a","time":1754957361000,"email":"devbali@berkeley.edu","author":"Dev Bali","message":"Rename README.md to basic-grammar.md"},{"hash":"5e7f42f90e739741159871d942e6bbe00448979f","time":1754599228000,"email":"72895702+KSPAtlas@users.noreply.github.com","author":"KSP Atlas","message":"another fix aaa"},{"hash":"06d10154977a0ab8bf75bb3afedc2fc4dd91ad17","time":1754599171000,"email":"72895702+KSPAtlas@users.noreply.github.com","author":"KSP Atlas","message":"fix broken tables"},{"hash":"eba38483f2cd47b981639eb5cda7e5bb2a5968e5","time":1754599018000,"email":"72895702+KSPAtlas@users.noreply.github.com","author":"KSP Atlas","message":"fix up the basic grammar page, I want to split this up later anyways"},{"hash":"508f4dd539dd9bc41a6b16f3a5de70b8e5bdd08b","time":1747868718000,"email":"kspatlas@disroot.org","author":"KSPAtlas","message":"redo some examples"},{"hash":"1b50c643449c91608e2953fec8a1cf59ddb5756a","time":1747257028000,"email":"kspatlas@disroot.org","author":"KSPAtlas","message":"Fix things"},{"hash":"5b76a0d49c2881a537407eed87a15eb74321d639","time":1746402350000,"email":"kspatlas@disroot.org","author":"KSPAtlas","message":"Initial commit"}]},"filePathRelative":"reference/basic-grammar.md"}`),u={name:`basic-grammar.md`},d={class:`hint-container warning`};function f(c,l,u,f,p,m){let h=t(`RouteLink`);return s(),o(`div`,null,[l[23]||=n(`<h1 id="basic-grammar" tabindex="-1"><a class="header-anchor" href="#basic-grammar"><span>Basic Grammar</span></a></h1><div class="hint-container warning"><p class="hint-container-title">Warning</p><p>This documentation may be incomplete, broken or inaccurate.</p></div><p>The essential details to get a grasp on Kokanu grammar and start exploring how to express yourself and communicate. The coverage is very fast paced and minimally detailed, more detailed articles are linked if you want to expand your knowledge of a given area.</p><p>This guide assumes you have some familiarity with the Kokanu vocabulary. Words that directly affect the grammar are explained here in the guide, but other words used in the example sentences will not. You can <strong>click</strong> on any described Kokanu word to see a definition of that word, and you can look up other words using the <a href="https://dictionary.kokanu.com/" target="_blank" rel="noopener noreferrer">dictionary</a>.</p><h2 id="base-forms" tabindex="-1"><a class="header-anchor" href="#base-forms"><span>Base Forms</span></a></h2><p>Every word has one base form, either base <strong>noun</strong>, base <strong>verb</strong>, or base <strong>modifier</strong>. Any word can act in any form, but its base determines how it acts in other forms. You can always distinguish when a word is being used as a <strong>noun</strong>, <strong>verb</strong> or <strong>modifier</strong>.</p><p>Verbs are marked by the particles <a href="https://dictionary.kokanu.com/le?lang=en" style="text-decoration:none;">le</a> and <a href="https://dictionary.kokanu.com/o?lang=en" style="text-decoration:none;">o</a>.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td><span class="red">ɞ̄ȷ ɞı</span> <span class="green">ʋȷ ɞx̄</span>:</td><td><span class="red">men mi</span> <span class="green">le makan</span>.<br></td><td><span class="red">I</span> <span class="green">eat</span>.</td></tr></tbody></table><p><strong>Nouns</strong> are marked by the <strong>prepositions</strong>, like <a href="https://dictionary.kokanu.com/men?lang=en" style="text-decoration:none;">men</a>, <a href="https://dictionary.kokanu.com/in?lang=en" style="text-decoration:none;">in</a>, <a href="https://dictionary.kokanu.com/ki?lang=en" style="text-decoration:none;">ki</a>, and <a href="https://dictionary.kokanu.com/wija?lang=en" style="text-decoration:none;">wija</a>.</p><p>And as you can probably see from the above example, there are no articles in Kokanu.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td><span class="red">ɞ̄ȷ ɞı</span> <span class="green">ʋȷ ɞx̄</span> <strong class="blue">ōı ɞx̄</strong>:</td><td><span class="red">men mi</span> <span class="green">le makan</span> <strong class="blue">in makan</strong>.</td><td><span class="red">I</span> <span class="green">eat</span> <strong class="blue">food</strong>.</td></tr></tbody></table><p><strong>Modifiers</strong> are activated when placed after a <strong>noun</strong> or <strong>verb</strong>.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td><span class="red">ɞ̄ȷ ɞı</span> <span class="green">ʋȷ ɞx̄</span> <strong class="yellow">ɕıxı</strong> <span class="blue">ōı xſɕʃɤı</span> <strong class="magenta">ɞx̄</strong>:</td><td><span class="red">men mi</span> <span class="green">le makan</span> <strong class="yellow">wiki</strong> <span class="blue">in kuwosi</span> <strong class="magenta">makan</strong>.</td><td><span class="red">I</span> <strong class="yellow">quickly</strong> <span class="green">eat</span> an <strong class="magenta">edible</strong> <span class="blue">fruit</span>.</td></tr></tbody></table>`,13),i(`p`,null,[l[1]||=e(`Check out the `,-1),a(h,{to:`/reference/word-derivations.html`},{default:r(()=>[...l[0]||=[e(`Word Derivations`,-1)]]),_:1}),l[2]||=e(` guide for more info.`,-1)]),l[24]||=n(`<hr><h2 id="noun-phrases-and-action-phrases" tabindex="-1"><a class="header-anchor" href="#noun-phrases-and-action-phrases"><span>Noun Phrases and Action Phrases</span></a></h2><p>The structure of a Kokanu sentence is formed from an <strong>action phrase</strong>, marked by <a href="https://dictionary.kokanu.com/le?lang=en" style="text-decoration:none;">le</a> or <a href="https://dictionary.kokanu.com/o?lang=en" style="text-decoration:none;">o</a>, surrounded by <strong>noun phrases</strong> which relate to the action in some way. <a href="https://dictionary.kokanu.com/men?lang=en" style="text-decoration:none;">men</a> marks a <strong>noun phrase</strong> which is the <strong>agent</strong> of the action. <a href="https://dictionary.kokanu.com/in?lang=en" style="text-decoration:none;">in</a> marks a <strong>noun phrase</strong> which is the object of the action. <a href="https://dictionary.kokanu.com/ki?lang=en" style="text-decoration:none;">ki</a> marks a <strong>noun phrase</strong> which is the recipient of the action. <a href="https://dictionary.kokanu.com/wija?lang=en" style="text-decoration:none;">wija</a> marks a <strong>noun phrase</strong> which is the instrument of the action. The <strong>action phrases</strong> and <strong>noun phrases</strong> can be placed in any order as long as they are marked properly.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td><span class="yellow">ɕıɂ ɞʃʌʃ</span> <span class="blue">ōı ɞx̄</span> <span class="green">ʋȷ ʋ̄ſ ʌɂʋı</span> <span class="red">ɞ̄ȷ ɞı</span>:</td><td><span class="yellow">wija moto</span> <span class="blue">in makan</span> <span class="green">le lun tajali</span> <span class="red">men mi</span>.</td><td><span class="red">I</span> <span class="green">prepare</span> <span class="blue">food</span> <span class="yellow">using fire</span>. / <span class="red">I</span> <span class="green">cook</span> <span class="blue">food</span>.</td></tr></tbody></table><p>When the subject is at the <em>start</em> of a sentence, however, <a href="https://dictionary.kokanu.com/men?lang=en" style="text-decoration:none;">men</a> can be dropped.</p><table><thead><tr><th>Likanu</th><th>Latin script</th></tr></thead><tbody><tr><td><span class="red">ɞ̄ȷ ɞı</span> <span class="green">ʋȷ ɞx̄</span>:</td><td><span class="red">men mi</span> <span class="green">le makan</span>.</td></tr><tr><td><span class="red">ɞı</span> <span class="green">ʋȷ ɞx̄</span>:</td><td><span class="red">mi</span> <span class="green">le makan</span>.</td></tr></tbody></table><hr><h2 id="negation" tabindex="-1"><a class="header-anchor" href="#negation"><span>Negation</span></a></h2><p><strong>Prepositions</strong>, certain particles, <a href="https://dictionary.kokanu.com/le?lang=en" style="text-decoration:none;">le</a>, and <a href="https://dictionary.kokanu.com/o?lang=en" style="text-decoration:none;">o</a> can be negated by placing <a href="https://dictionary.kokanu.com/no?lang=en" style="text-decoration:none;">no</a> after them. <a href="https://dictionary.kokanu.com/no?lang=en" style="text-decoration:none;">no</a> does <em>not</em> negate content words, only certain grammatical particles. However, <a href="https://dictionary.kokanu.com/no?lang=en" style="text-decoration:none;">no</a> can also be used to negate specific attributes of a phrase by negating said particles, which will be explained later.</p><p>These three sentences mean the same thing but have different emphasis:</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td><span class="red">ɞı</span> <strong class="green">ʋȷ</strong> <strong class="yellow">ƨʃ</strong> <strong class="green">ɞx̄</strong> <span class="blue">ōı xſɕʃɤı</span>:</td><td><span class="red">mi</span> <strong class="green">le</strong> <strong class="yellow">no</strong> <strong class="green">makan</strong> <span class="blue">in kuwosi</span>.</td><td><span class="red">I</span> <strong class="yellow">don’t</strong> <strong class="green">eat</strong> <span class="blue">fruit</span>. (<strong>no emphasis</strong> <em>or</em> but I may do something else to it)</td></tr><tr><td><span class="red">ɞı</span> <span class="green">ʋȷ ɞx̄</span> <strong class="blue">ōı</strong> <strong class="yellow">ƨʃ</strong> <strong class="blue">xſɕʃɤı</strong>:</td><td><span class="red">mi</span> <span class="green">le makan</span> <strong class="blue">in</strong> <strong class="yellow">no</strong> <strong class="blue">kuwosi</strong>.</td><td><span class="red">I</span> <strong class="yellow">don’t</strong> <span class="green">eat</span>\xA0<strong class="blue">fruit</strong>. (but I may eat something else)</td></tr><tr><td><strong class="red">ɞ̄ȷ</strong> <strong class="yellow">ƨʃ</strong> <strong class="red">ɞı</strong> <span class="green">ʋȷ ɞx̄</span> <span class="blue">ōı xſɕʃɤı</span>:</td><td><strong class="red">men</strong> <strong class="yellow">no</strong> <strong class="red">mi</strong> <span class="green">le makan</span> <span class="blue">in kuwosi</span>.</td><td><strong class="red">I</strong> <strong class="yellow">don’t</strong> <span class="green">eat</span> <span class="blue">fruit</span>. (but someone/thing else may)</td></tr></tbody></table><p>In order to negate the entire phrase, with no emphasis on any specific part being negated, <a href="https://dictionary.kokanu.com/no?lang=en" style="text-decoration:none;">no</a> is placed after the verb-marking particle (either <a href="https://dictionary.kokanu.com/le?lang=en" style="text-decoration:none;">le</a> or <a href="https://dictionary.kokanu.com/o?lang=en" style="text-decoration:none;">o</a>). This is how you normally negate phrases (i.e. &quot;I didn&#39;t see the dog&quot;). However, putting <a href="https://dictionary.kokanu.com/no?lang=en" style="text-decoration:none;">no</a> after the verb-marking particle is <em>also</em> the way to put emphasis on the fact that the verb alone is being negated.</p><p>Depending on context, and the tone of the speaker, the negation of the of the verb-marking particle <em>may</em> imply that specifically and only the verb is being negated, <em>or</em> that the entire phrase is being negated. The default assumption is usually that there is no specific emphasis on the verb, and the sentence is being normally negated, as the negation of specifically the verb can be communicated in other ways (most chiefly, italics when in text, or tone when spoken).</p><hr><h2 id="conjunctions" tabindex="-1"><a class="header-anchor" href="#conjunctions"><span>Conjunctions</span></a></h2><p>Conjunctions in Kokanu can be placed between nouns in a phrase, or between sentences.</p><p>However, <a href="https://dictionary.kokanu.com/un?lang=en" style="text-decoration:none;">un</a>, meaning &quot;and&quot;, is not required like it is in English. In phrases where two nouns of the same function are next to each other (e.g. me <strong>and</strong> you go to the park), &quot;un&quot; may be used on its own, the preposition may be repeated, or both strategies may be combined. <a href="https://dictionary.kokanu.com/un?lang=en" style="text-decoration:none;">un</a> may still be used to connect sentences together like in English.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td><span class="red">ɞı</span> <span class="green">ʋȷ ɞx̄</span> <span class="blue">ōı xſɕʃɤı</span> <strong class="yellow">ōſ</strong> <span class="blue">oſxɞ</span>:</td><td><span class="red">mi</span> <span class="green">le makan</span> <span class="blue">in kuwosi</span> <strong class="yellow">un</strong> <span class="blue">ukama</span>.</td><td><span class="red">I</span> <span class="green">eat</span> <span class="blue">fruits</span> <strong class="yellow">and</strong> <span class="blue">vegetables</span>.</td></tr><tr><td><span class="red">ɞı</span> <span class="green">ʋȷ ɞx̄</span> <span class="blue">ōı xſɕʃɤı <strong>ōı</strong> oſxɞ</span>:</td><td><span class="red">mi</span> <span class="green">le makan</span> <span class="blue">in kuwosi <strong>in</strong> ukama</span>.</td><td><span class="red">I</span> <span class="green">eat</span> <span class="blue">fruits <strong>and</strong> vegetables</span>.</td></tr><tr><td><span class="red">ɞı</span> <span class="green">ʋȷ ɞx̄</span> <span class="blue">ōı xſɕʃɤı</span> <span class="yellow"><strong>ōſ</strong></span> <span class="blue"><strong>ōı</strong> oſxɞ</span>:</td><td><span class="red">mi</span> <span class="green">le makan</span> <span class="blue">in kuwosi</span> <strong class="yellow">un</strong> <span class="blue"><strong>in</strong> ukama</span>.</td><td><span class="red">I</span> <span class="green">eat</span> <span class="blue">fruits</span> <strong class="yellow">and</strong> <span class="blue">vegetables</span>.</td></tr><tr><td><span class="red">ɞı</span> <span class="green">ʋȷ ɞx̄</span> <span class="blue">ōı xſɕʃɤı</span> <strong class="yellow">ōſ</strong> <span class="red">ɞı</span> <span class="green">ʋȷ ʋʃ</span> <span class="magenta">ʜı ƨȷ ɂ̄</span>:</td><td><span class="red">mi</span> <span class="green">le makan</span> <span class="blue">in kuwosi</span> <strong class="yellow">un</strong> <span class="red">mi</span> <span class="green">le lo</span> <span class="magenta">pi ne jan</span>.</td><td><span class="red">I</span> <span class="green">eat</span> <span class="blue">fruits</span> <strong class="yellow">and</strong> <span class="red">I</span> <span class="green">move</span> (<span class="magenta">within this place</span>).</td></tr></tbody></table><hr><h2 id="suggestions-and-imperatives" tabindex="-1"><a class="header-anchor" href="#suggestions-and-imperatives"><span>Suggestions and Imperatives</span></a></h2><p>An imperative statement is created by replacing <a href="https://dictionary.kokanu.com/le?lang=en" style="text-decoration:none;">le</a> with <a href="https://dictionary.kokanu.com/o?lang=en" style="text-decoration:none;">o</a>. When there is a subject in the phrase, the phrase is usually interpreted as a suggestion, however if the subject is dropped, the phrase is usually interpreted as a command.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td><span class="red">ʌſ</span> <span class="green">ʋȷ ʋʃ</span>:</td><td><span class="red">tu</span> <span class="green">le lo</span>.</td><td><span class="red">You</span> <span class="green">move</span>.</td></tr><tr><td><span class="red">ʌſ</span> <span class="green">oʃ ʋʃ</span>ʭ</td><td><span class="red">tu</span> <span class="green">o lo</span>!</td><td><span class="red">You</span> <span class="green">should move</span>!</td></tr><tr><td><span class="green">oʃ ʋʃ</span>ʭ</td><td><span class="green">o lo</span>!</td><td><span class="green">Move</span>!</td></tr><tr><td><span class="red">ɵȷ ʌſ</span> <span class="green">oʃ ʋʃ</span>ʭ</td><td><span class="red">he tu</span> <span class="green">o lo</span>!</td><td><span class="red">Hey you</span>, <span class="green">move</span>!</td></tr></tbody></table>`,22),i(`p`,null,[l[4]||=e(`For more information, see `,-1),a(h,{to:`/reference/using-the-parts-of-speech.html`},{default:r(()=>[...l[3]||=[e(`Using the Parts of Speech`,-1)]]),_:1}),l[5]||=e(`.`,-1)]),l[25]||=n(`<hr><h2 id="modifiers" tabindex="-1"><a class="header-anchor" href="#modifiers"><span>Modifiers</span></a></h2><p>Remember that depending on the context, all words can act as a <strong>noun</strong>, <strong>modifier</strong>, or <strong>verb</strong>. Which one a word acts as depends upon where it is placed in a sentence.</p><p><strong>Modifiers</strong> come after a <strong>noun</strong> to indicate an <strong>adjective</strong>, or after a <strong>verb</strong> to indicate an <strong>adverb</strong>. This means that any time a content word comes after another content word in succession, the latter content word acts as a modifier. This means that all adjectives and adverbs come <em>after</em> the words that they modify, the opposite of English.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td>ɂ̄ <span class="yellow">ʌʃʜȷ</span></td><td>jan <span class="yellow">tope</span></td><td><span class="yellow">good</span> place</td></tr><tr><td>ʜɕʃ <span class="yellow">xſɤ</span></td><td>pawo <span class="yellow">kusa</span></td><td><span class="yellow">angry</span> dog</td></tr><tr><td>ʜʌ̄ſ <span class="yellow">ʜſɞı</span></td><td>patun <span class="yellow">pumi</span></td><td><span class="yellow">land-related</span> stillness</td></tr><tr><td>ɞx̄ <span class="yellow">ʌſxʃ ʜ</span></td><td>makan <span class="yellow">tuko pa</span></td><td><span class="yellow">hot touchable</span> food</td></tr><tr><td>xſɕʃɤı <span class="yellow">ɤȷʜʃ ɕ̄xſ</span></td><td>kuwosi <span class="yellow">sepo wanku</span></td><td><span class="yellow">curved yellow</span> fruit</td></tr></tbody></table><p>Unlike in English, where certain adjective order can feel weird, or even alter meaning, there is no specific modifier order in Kokanu.</p><ul><li><p>pawo <span class="yellow">hunsi cenpo</span> / ʜɕʃ <span class="yellow">ɵ̄ſɤı ɛ̄ȷʜʃ</span></p></li><li><p>pawo <span class="yellow">cenpo hunsi</span> / ʜɕʃ <span class="yellow">ɛ̄ȷʜʃ ɵ̄ſɤı</span><br> (Both sound fine!)</p></li><li><p>Big red dog (sounds fine!)</p></li><li><p>Red big dog (wha?)</p></li></ul><p>The only place where this doesn&#39;t apply is in lexicalized phrases. Certain lexicalized phrases can sound a bit weird, or even not be recognized, if their noun and modifier components are split apart.</p><hr><h2 id="quantities" tabindex="-1"><a class="header-anchor" href="#quantities"><span>Quantities</span></a></h2><p><strong>Quantity words</strong> are words that serve special grammatical function, and that have multiple meanings depending on where they&#39;re placed. There are two types of quantity words: numbers and amounts.</p><p>Quantity words may be placed in two different places, and where they&#39;re placed affects meaning. Quantity words serve an ordinary purpose as modifiers, but serve an additional function when <em>preceding</em> nouns.</p><p>When quantity words which are <strong>numbers</strong> (e.g. one, seven, nine, a hundred, etc.) are used as <strong>modifiers</strong> (i.e. placed after the head word), they act as <strong>ordinals</strong> (<em>1st</em> place, the <em>100th</em> dog, the <em>8th</em> person). But when they are placed before the head word, they act as <strong>cardinals</strong> (<em>one</em> dog, <em>a hundred</em> cats, <em>four</em> cars).</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td>xſɕʃɤı <span class="yellow">ɕ̄</span></td><td>kuwosi <span class="yellow">wan</span></td><td><span class="yellow">first</span> fruit</td></tr><tr><td><span class="yellow">ɕ̄</span> xſɕʃɤı</td><td><span class="yellow">wan</span> kuwosi</td><td><span class="yellow">one</span> fruit</td></tr><tr><td>ʜʌ <span class="yellow">ɤȷʌ̄</span></td><td>pata <span class="yellow">setan</span></td><td><span class="yellow">seventh</span> document</td></tr><tr><td><span class="yellow">ɤȷʌ̄</span> ʜʌ</td><td><span class="yellow">setan</span> pata</td><td><span class="yellow">seven</span> documents</td></tr><tr><td>ʜɕʃ <span class="yellow">ɤıɂ̄ȷ</span></td><td>pawo <span class="yellow">sijen</span></td><td><span class="yellow">one hundredth</span> dog</td></tr><tr><td><span class="yellow">ɤıɂ̄ȷ</span> ʜɕʃ</td><td><span class="yellow">sijen</span> pawo</td><td><span class="yellow">one hundred</span> dogs</td></tr></tbody></table><p>When quantity words which are <strong>amounts</strong> (e.g. a lot, some, all, more) are used as <strong>modifiers</strong> (i.e. placed after the head word), they act to determine <strong>the intensity</strong>. But when they are placed before the head word, they act to determine <strong>the amount</strong>.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td>ʌʃʜȷ <span class="yellow">ʋ̄</span></td><td>tope <span class="yellow">jati</span></td><td><span class="yellow">somewhat</span> good</td></tr><tr><td><span class="yellow">ʋ̄</span> ʌʃʜȷ</td><td><span class="yellow">jati</span> tope</td><td><span class="yellow">some</span> goodnesses</td></tr><tr><td>ɞı <span class="yellow">ʋ̄</span></td><td>mi <span class="yellow">lan</span></td><td>very (much) me</td></tr><tr><td><span class="yellow">ʋ̄</span> ɞı</td><td><span class="yellow">lan</span> mi</td><td>we</td></tr><tr><td>ƨȷɂȷ <span class="yellow">ɂʌı</span></td><td>neje <span class="yellow">jati</span></td><td><span class="yellow">somewhat</span> horse-like</td></tr><tr><td>ɂʌı] <span class="yellow">ƨȷɂȷ</span></td><td><span class="yellow">jati</span> neje</td><td><span class="yellow">some</span> horses</td></tr><tr><td>ʋɞʃ <span class="yellow">oƨı</span></td><td>lamo <span class="yellow">ani</span></td><td><span class="yellow">most</span> long / long<span class="yellow">est</span></td></tr><tr><td><span class="yellow">oƨı</span> ʋɞʃ</td><td><span class="yellow">ani</span> lamo</td><td><span class="yellow">all of the</span> lengths</td></tr><tr><td>ʜɤ̄ <span class="yellow">ɞȷɤȷ</span></td><td>pasan <span class="yellow">mese</span></td><td><span class="yellow">more</span> happy / happ<span class="yellow">ier</span></td></tr><tr><td><span class="yellow">ɞȷɤȷ</span> ʜɤ̄</td><td><span class="yellow">mese</span> pasan</td><td><span class="yellow">more</span> happinesses</td></tr><tr><td><span class="yellow">ɞȷɤȷ</span> ʜɤ̄</td><td><span class="green">le pasan mese</span> <span class="red">men lan mi</span></td><td><span class="red">we</span> <span class="green">are happier</span></td></tr></tbody></table>`,16),i(`div`,d,[l[9]||=i(`p`,{class:`hint-container-title`},`Warning`,-1),l[10]||=i(`p`,null,[e(`Although `),i(`a`,{href:`https://dictionary.kokanu.com/tope?lang=en`,style:{"text-decoration":`none`}},`tope`),e(),i(`a`,{href:`https://dictionary.kokanu.com/jati?lang=en`,style:{"text-decoration":`none`}},`jati`),e(` is written as "somewhat good", this is not what it would mean as a noun. It would indeed mean "somewhat good" when acting as a modifier, but acting as a noun it would instead mean "somewhat goodness".`)],-1),l[11]||=i(`p`,null,[e(`The examples where the quantity word came `),i(`em`,null,`after`),e(` the head word had their modifier-meaning shown, but the examples where the quantity word came `),i(`em`,null,`before`),e(` the head word had their noun-meaning shown. This was in order to ease understanding of what the quantity words actually did.`)],-1),i(`p`,null,[l[7]||=e(`The page on `,-1),a(h,{to:`/reference/word-derivations.html`},{default:r(()=>[...l[6]||=[e(`Word Derivations`,-1)]]),_:1}),l[8]||=e(` describes how these word class conversions operate.`,-1)])]),l[26]||=n(`<hr><h2 id="demonstratives" tabindex="-1"><a class="header-anchor" href="#demonstratives"><span>Demonstratives</span></a></h2><p><strong>Demonstratives</strong> are a word class that function similarily to quantity words. When placed before the head word, they act as determiners, and signify which <em>noun</em> is being talked about. When placed after the head word (i.e. when acting as modifiers), demonstratives stand in as a modifier, and signify which <em>modifier</em> is being talked about.</p><p>There are only three demonstratives: <a href="https://dictionary.kokanu.com/ne?lang=en" style="text-decoration:none;">ne</a> (this), <a href="https://dictionary.kokanu.com/na?lang=en" style="text-decoration:none;">na</a> (that), and <a href="https://dictionary.kokanu.com/ci?lang=en" style="text-decoration:none;">ci</a> (what).</p><p>When placed before the head word, they act exactly as you would expect them to in English.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td><span class="yellow">ƨ</span> xſɕʃɤı</td><td><span class="yellow">na</span> kuwosi</td><td><span class="yellow">that</span> fruit</td></tr><tr><td><span class="yellow">ƨȷ</span> ʋıx</td><td><span class="yellow">ne</span> lika</td><td><span class="yellow">this</span> text</td></tr><tr><td><span class="yellow">ɛı</span> ɂ̄</td><td><span class="yellow">ci</span> jan</td><td><span class="yellow">what</span> place</td></tr></tbody></table><p>However, when placed <em>after</em> the head word, they instead act to stand in for a modifier. Using the example of <a href="https://dictionary.kokanu.com/na?lang=en" style="text-decoration:none;">na</a>, this would mean that putting <a href="https://dictionary.kokanu.com/na?lang=en" style="text-decoration:none;">na</a> after a head word would mean something along the lines of &quot;like that&quot; or &quot;that kind of&quot;.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td>xſɕʃɤı <span class="yellow">ƨ</span></td><td>kuwosi <span class="yellow">na</span></td><td>fruit <span class="yellow">like that</span> / <span class="yellow">that kind of</span> fruit</td></tr><tr><td>ʋıx <span class="yellow">ƨȷ</span></td><td>lika <span class="yellow">ne</span></td><td>text <span class="yellow">like this</span> / <span class="yellow">that kind of</span> text</td></tr><tr><td>ɂ̄ <span class="yellow">ɛı</span></td><td>jan <span class="yellow">ci</span></td><td>place <span class="yellow">like what</span> / <span class="yellow">what kind of</span> place</td></tr></tbody></table><p>Note: the word <a href="https://dictionary.kokanu.com/soto?lang=en" style="text-decoration:none;">soto</a> can be used to communicate this more explicitly, and they have a decently similar meaning, but different nuance.</p><hr><h2 id="genitives" tabindex="-1"><a class="header-anchor" href="#genitives"><span>Genitives</span></a></h2><p>The word <a href="https://dictionary.kokanu.com/je?lang=en" style="text-decoration:none;">je</a> is a <strong>genitive</strong>, similar to the word “of” in English. The word following it is always derived as a <strong>noun</strong>. It can be used to regroup phrases.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td>ʌıʜ <span class="yellow">ɞx̄</span></td><td>tipa <span class="yellow">makan</span></td><td><span class="yellow">edible</span> box</td></tr><tr><td>ʌıʜ <span class="magenta">ɂȷ</span> <span class="yellow">ɞx̄</span></td><td>tipa <span class="magenta">je</span> <span class="yellow">makan</span></td><td><span class="yellow">food</span> box, <span class="yellow">lunch</span>box</td></tr><tr><td>xſɕʃɤı <span class="yellow">ɵ</span> <span class="magenta">ɞı</span></td><td>kuwosi <span class="yellow">ha</span> <span class="magenta">mi</span></td><td><span class="magenta">my</span> <span class="yellow">second</span> fruit</td></tr><tr><td>xſɕʃɤı <span class="green">ɂȷ</span> <span class="yellow">ɵ</span> <span class="magenta">ɞı</span></td><td>kuwosi <span class="green">je</span> <span class="yellow">ha</span> <span class="magenta">mi</span></td><td><span class="magenta">us</span> <span class="yellow">two</span><span class="green">’s</span> fruit</td></tr></tbody></table><p>The word <a href="https://dictionary.kokanu.com/wa?lang=en" style="text-decoration:none;">wa</a> <strong>collapses</strong> the entire phrase before it and marks the word after it as a a <strong>modifier</strong>.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td>xſɕʃɤı <span class="green">ɂȷ</span> <span class="yellow">ɵ ɞı</span> <span class="magenta">ɕ</span> <span class="red">ɵ̄ſɤı</span></td><td>kuwosi <span class="green">je</span> <span class="yellow">ha mi</span> <span class="magenta">wa</span> <span class="red">hunsi</span></td><td><span class="yellow">us two</span><span class="green">’s</span> <span class="red">red</span> fruit</td></tr></tbody></table>`,15),i(`p`,null,[l[13]||=e(`For more information, refer to our `,-1),a(h,{to:`/reference/clarifying-descriptions.html`},{default:r(()=>[...l[12]||=[e(`Clarifying Descriptions`,-1)]]),_:1}),l[14]||=e(` guide.`,-1)]),l[27]||=n(`<hr><h2 id="subordinate-clauses" tabindex="-1"><a class="header-anchor" href="#subordinate-clauses"><span>Subordinate Clauses</span></a></h2><p><a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a> starts a <strong>subordinate clause</strong>. It can be roughly translated as &quot;the fact that&quot; or &quot;that&quot; in English. Any clause made by <a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a> is treated as a <strong>noun</strong>.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td><span class="red">ɞı</span> <span class="green">ʋȷ xƨıɤ</span> <span class="blue">ōı</span> <strong>ʌ</strong> <span class="red">ƨ</span> <span class="green">ʋȷ ʌʃʜȷ</span></td><td><span class="red">mi</span> <span class="green">le kanisa</span> <span class="blue">in</span> <strong>ta</strong> <span class="red">na</span> <span class="green">le tope</span></td><td><span class="red">I</span> <span class="green">think</span> <strong>that</strong> <span class="red">that</span> <span class="green">is good</span></td></tr><tr><td><span class="green">ʋȷ xıxſɕ</span> <span class="red">ɞ̄ȷ</span> <strong>ʌ</strong> <span class="red">ʌſ</span> <span class="green">ʋȷ xʃʌ</span> <span class="blue">ōı ƨ</span></td><td><span class="green">le kikuwa</span> <span class="red">men</span> <strong>ta</strong> <span class="red">tu</span> <span class="green">le kota</span> <span class="blue">in na</span></td><td><span class="green">It&#39;s weird</span> <strong>that</strong> <span class="red">you</span> <span class="green">say</span> <span class="blue">that</span></td></tr></tbody></table><p>If <a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a> comes before <a href="https://dictionary.kokanu.com/in?lang=en" style="text-decoration:none;">in</a> (i.e. <a href="https://dictionary.kokanu.com/in?lang=en" style="text-decoration:none;">in</a> <a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a>), you can optionally drop the <a href="https://dictionary.kokanu.com/in?lang=en" style="text-decoration:none;">in</a>.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td><span class="red">ɞı</span> <span class="green">ʋȷ xƨıɤ</span> <strong>ʌ</strong> <span class="red">ƨ</span> <span class="green">ʋȷ ʌʃʜȷ</span></td><td><span class="red">mi</span> <span class="green">le kanisa</span> <strong>ta</strong> <span class="red">na</span> <span class="green">le tope</span></td><td><span class="red">I</span> <span class="green">think</span> <strong>that</strong> <span class="red">that</span> <span class="green">is good</span></td></tr></tbody></table><p><a href="https://dictionary.kokanu.com/te?lang=en" style="text-decoration:none;">te</a>, similar to <a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a>, starts a <strong>subordinate clause</strong>, however, different to <a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a>, any word after <a href="https://dictionary.kokanu.com/te?lang=en" style="text-decoration:none;">te</a> is marked as a <strong>verb</strong>. An easy way to think about <a href="https://dictionary.kokanu.com/te?lang=en" style="text-decoration:none;">te</a> clauses as an English speaker is that whereas <a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a> translates to &quot;that&quot;, <a href="https://dictionary.kokanu.com/te?lang=en" style="text-decoration:none;">te</a> translates to &quot;to&quot; or &quot;-ing&quot;.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td><span class="red">ɞı</span> <span class="green">ʋȷ ɂſ</span> <span class="blue">ōı</span> <strong>ʌȷ</strong> <span class="green">ʜʌ</span> <span class="blue">ōı ʋıx</span></td><td><span class="red">mi</span> <span class="green">le ju</span> <span class="blue">in</span> <strong>te</strong> <span class="green">pata</span> <span class="blue">in lika</span></td><td><span class="red">I</span> <span class="green">want</span> <strong>to</strong> <span class="green">read</span> <span class="blue">text</span></td></tr><tr><td><span class="green">ʋȷ ɤʌʋ̄</span> <span class="red">ɞ̄ȷ</span> <strong>ʌȷ</strong> <span class="green">ɞx̄</span> <span class="blue">ōı xſɕʃɤı</span></td><td><span class="green">le satalan</span> <span class="red">men</span> <strong>te</strong> <span class="green">makan</span> <span class="blue">in kuwosi</span></td><td><span class="green">It&#39;s normal</span> <strong>to</strong> <span class="green">eat</span> <span class="blue">fruit</span></td></tr><tr><td><span class="red">ɞ̄ȷ</span> <strong>ʌȷ</strong> <span class="green">ʜ̄ȷ</span> <span class="blue">ōı ‹xʃxƨſ›</span>､ <span class="green">ʋȷ xʌ̄ı</span></td><td><span class="red">men</span> <strong>te</strong> <span class="green">pen</span> <span class="blue">in Kokanu</span>, <span class="green">le katin</span></td><td><span class="green">Understanding</span> <span class="blue">Kokanu</span> <span class="green">is difficult</span></td></tr></tbody></table><p>Just like <a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a>, if <a href="https://dictionary.kokanu.com/te?lang=en" style="text-decoration:none;">te</a> comes before <a href="https://dictionary.kokanu.com/in?lang=en" style="text-decoration:none;">in</a> (i.e. <a href="https://dictionary.kokanu.com/in?lang=en" style="text-decoration:none;">in</a> <a href="https://dictionary.kokanu.com/te?lang=en" style="text-decoration:none;">te</a>), you can optionally drop the <a href="https://dictionary.kokanu.com/in?lang=en" style="text-decoration:none;">in</a>.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td><span class="red">ɞı</span> <span class="green">ʋȷ ɂſ</span> <strong>ʌȷ</strong> <span class="green">ʜʌ</span> <span class="blue">ōı ʋıx</span></td><td><span class="red">mi</span> <span class="green">le ju</span> <strong>te</strong> <span class="green">pata</span> <span class="blue">in lika</span></td><td><span class="red">I</span> <span class="green">want</span> <strong>to</strong> <span class="green">read</span> <span class="blue">text</span></td></tr></tbody></table><hr><h2 id="relative-clauses" tabindex="-1"><a class="header-anchor" href="#relative-clauses"><span>Relative Clauses</span></a></h2><p><a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a> and <a href="https://dictionary.kokanu.com/te?lang=en" style="text-decoration:none;">te</a> can also modify nouns.</p><p>When <a href="https://dictionary.kokanu.com/te?lang=en" style="text-decoration:none;">te</a> is placed after a noun, it starts a relative clause where the noun that it is modifying is the subject. Any word that comes after <a href="https://dictionary.kokanu.com/te?lang=en" style="text-decoration:none;">te</a> is assumed to be a verb.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td><span class="red">ʜɕʃ</span> <strong>ʌȷ</strong> <span class="green">ɞx̄</span> <span class="blue">ōı xſɕʃɤı</span>:</td><td><span class="red">pawo</span> <strong>te</strong> <span class="green">makan</span> <span class="blue">in kuwosi</span>.</td><td><span class="red">The dog</span> <strong>that</strong> <span class="green">eats</span> <span class="blue">fruit</span>.</td></tr><tr><td><span class="red">ɞı</span> <span class="green">ʋȷ ɕıɤ̄</span> <span class="blue">ōı ƨ̄ı</span> <strong>ʌȷ</strong> <span class="green">ʌɂ̄ȷ</span> <span class="blue">ōı ɞı</span>:</td><td><span class="red">mi</span> <span class="green">le wisan</span> <span class="blue">in nin</span> <strong>te</strong> <span class="green">tajen</span> <span class="blue">in mi</span>.</td><td><span class="red">I</span> <span class="green">know</span> <span class="blue">the person</span> <strong>that</strong> <span class="green">hates</span> <span class="blue">me</span></td></tr><tr><td><span class="red">ɞı</span> <span class="green">ʋȷ ʌȷx</span> <span class="blue">ōı ʜſɞı</span> <strong>ʌȷ</strong> <span class="green">xſɞı</span>:</td><td><span class="red">mi</span> <span class="green">le teka</span> <span class="blue">in pumi</span> <strong>te</strong> <span class="green">kumi</span>.</td><td><span class="red">I</span> <span class="green">see</span> <span class="blue">the land</span> <strong>that</strong> <span class="green">is plastic</span>.</td></tr><tr><td><span class="purple">x</span> <span class="green">ʋȷ ɤȷ</span> <span class="red">ɞ̄ȷ ʜſʋſɤı</span> <strong>ʌȷ</strong> <span class="green">ʜ̄ɤ̄ı</span>≈</td><td><span class="purple">ka</span> <span class="green">le se</span> <span class="red">men pulusi</span> <strong>te</strong> <span class="green">pansin</span>?</td><td><span class="purple">Do</span> <span class="red">reptiles</span> <strong>that</strong> <span class="green">are squares</span> <span class="green">exist</span>?</td></tr></tbody></table><p>When <a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a> is placed after a noun, it also starts a relative clause. However, the role of the word that it modifies can be specified in two ways: it can reference back to itself using &quot;ja&quot;, or it can use a dangling preposition (which is what is primarily used in English). It can be thought of as similar to the word &quot;that&quot;. Any word that comes after <a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a> is assumed to be the subject of the relative clause.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td>ɂ̄ <strong>ʌ</strong> <span class="red">ɞı</span> <span class="green">ʋȷ ʋʃ</span> <span class="purple">xı</span></td><td>jan <strong>ta</strong> <span class="red">mi</span> <span class="green">le lo</span> <span class="purple">ki</span></td><td>place <strong>that</strong> <span class="red">I</span> <span class="green">go</span> <span class="purple">to</span></td></tr><tr><td>ƨ̄ı <strong>ʌ</strong> <span class="green">ʋȷ ɂʃʋı</span> <span class="red">ɞ̄ȷ ɞı</span> <span class="purple">ʜʃ</span></td><td>nin <strong>ta</strong> <span class="green">le joli</span> <span class="red">men mi</span> <span class="purple">po</span></td><td>person <strong>that</strong> <span class="red">I</span> <span class="green">am beneficial</span> <span class="purple">towards</span></td></tr><tr><td>ɂ̄ʃ <strong>ʌ</strong> <span class="purple">ɕıɂ ɂ</span> <span class="red">ɞ̄ȷ ɞı</span> <span class="green">ʋȷ ɞx̄</span></td><td>jon <strong>ta</strong> <span class="purple">wija ja</span> <span class="red">men mi</span> <span class="green">le makan</span></td><td>tool <strong>that</strong> <span class="red">I</span> <span class="green">eat</span> <span class="purple">with</span></td></tr><tr><td>ʌ̄ȷ <strong>ʌ</strong> <span class="green">ʋȷ ʌȷx</span> <span class="blue">ōı xſxſ</span> <span class="purple">ʜı ɂ</span> <span class="red">ɞ̄ȷ ɞı</span></td><td>ten <strong>ta</strong> <span class="green">le teka</span> <span class="blue">in kuku</span> <span class="purple">pi ja</span> <span class="red">men mi</span></td><td>time <strong>that</strong> <span class="red">I</span> <span class="green">see</span> <span class="blue">birds</span> <span class="purple">during</span></td></tr></tbody></table><p>Notice here how there&#39;s <em>always</em> a preposition that clarifies the role of the word that <a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a> is modifying. <a href="https://dictionary.kokanu.com/nin?lang=en" style="text-decoration:none;">nin</a> <a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a> <a href="https://dictionary.kokanu.com/mi?lang=en" style="text-decoration:none;">mi</a> <a href="https://dictionary.kokanu.com/le?lang=en" style="text-decoration:none;">le</a> <a href="https://dictionary.kokanu.com/suki?lang=en" style="text-decoration:none;">suki</a> might seem like a direct translation from English &quot;person that I like&quot;, but in Kokanu it&#39;s meaningless. The clause <a href="https://dictionary.kokanu.com/mi?lang=en" style="text-decoration:none;">mi</a> <a href="https://dictionary.kokanu.com/le?lang=en" style="text-decoration:none;">le</a> <a href="https://dictionary.kokanu.com/suki?lang=en" style="text-decoration:none;">suki</a> sits next to the word <a href="https://dictionary.kokanu.com/nin?lang=en" style="text-decoration:none;">nin</a> with no relation between them. It would be like saying in English &quot;place that I go&quot;. You have to establish the role of &quot;place&quot; in the clause &quot;I go&quot;, i.e. &quot;place that I go <strong>to</strong>&quot; where &quot;to&quot; tells you that &quot;place&quot; is the direction/goal of the clause &quot;I go&quot;. Kokanu does this in a very similar way.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td>ƨ̄ı <strong>ʌ</strong> <span class="red">ɞı</span> <span class="green">ʋȷ ɤſxı</span> <span class="blue">ōı</span></td><td>nin <strong>ta</strong> <span class="red">mi</span> <span class="green">le suki</span> <span class="blue">in</span></td><td>person <strong>that</strong> <span class="red">I</span> <span class="green">like</span></td></tr><tr><td>xȷʋ <strong>ʌ</strong> <span class="blue">ōı ɂ</span> <span class="red">ɞ̄ȷ ɞı</span> <span class="green">ʋȷ xȷʋ</span></td><td>kela <strong>ta</strong> <span class="blue">in ja</span> <span class="red">men mi</span> <span class="green">le kela</span></td><td>game <strong>that</strong> <span class="red">I</span> <span class="green">play</span></td></tr><tr><td>ɤ̄ı <strong>ʌ</strong> <span class="green">ʋȷ ʌȷx</span> <span class="red">ɞ̄ȷ ɞı</span> <span class="blue">ōı ɂ</span></td><td>sin <strong>ta</strong> <span class="green">le teka</span> <span class="red">men mi</span> <span class="blue">in ja</span></td><td>thing <strong>that</strong> <span class="red">I</span> <span class="green">see</span></td></tr><tr><td>ɞx̄ <strong>ʌ</strong> <span class="red">ɞ̄ȷ ɞı</span> <span class="green">ʋȷ ɞx̄</span> <span class="blue">ōı</span></td><td>makan <strong>ta</strong> <span class="red">men mi</span> <span class="green">le makan</span> <span class="blue">in</span></td><td>food <strong>that</strong> <span class="red">I</span> <span class="green">eat</span></td></tr></tbody></table><p>Remember, just as how <a href="https://dictionary.kokanu.com/men?lang=en" style="text-decoration:none;">men</a> is never required at the start of sentences, <a href="https://dictionary.kokanu.com/men?lang=en" style="text-decoration:none;">men</a> is never required after <a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a>. The word that comes after <a href="https://dictionary.kokanu.com/ta?lang=en" style="text-decoration:none;">ta</a> is always assumed to be the subject.</p><p>In any case, the clause must end with a comma if more follows.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td><span class="red">xſɕʃɤı</span> <strong>ʌ</strong> <span class="red">ƨ̄ı</span> <span class="green">ʋȷ ɞx̄</span> <span class="blue">ōı</span>､ <span class="green">ʋȷ ʌʃʜȷ</span>:</td><td><span class="red">kuwosi</span> <strong>ta</strong> <span class="red">nin</span> <span class="green">le makan</span> <span class="blue">in</span>, <span class="green">le tope</span>.</td><td>The fruit <strong>that</strong> the person ate is good.</td></tr><tr><td><span class="green">ʋȷ ɤſxı</span> <span class="blue">ōı ƨ oſxɞ</span> <strong>ʌ</strong> <span class="green">ʋȷ ɞx̄</span> <span class="red">ɞ̄ȷ ɞı</span> <span class="blue">ōı</span>､ <span class="red">ɞ̄ȷ ʌſ</span></td><td><span class="green">le suki</span> <span class="blue">in na ukama</span> <strong>ta</strong> <span class="green">le makan</span> <span class="red">men mi</span> <span class="blue">in</span>, <span class="red">men tu</span>.</td><td><span class="red">You</span> <span class="green">like</span> <span class="blue">that plant</span> <strong>that</strong> <span class="red">I</span> <span class="green">ate</span></td></tr><tr><td><span class="red">ƨ̄ı</span> <strong>ʌ</strong> <span class="red">ɞı</span> <span class="green">ʋȷ ʜ̄ıxʃ</span> <span class="blue">ōı</span>､ <span class="green">ʋȷ ƨʃ ɤſxı</span> <span class="blue">ōı ɞı</span></td><td><span class="red">nin</span> <strong>ta</strong> <span class="red">mi</span> <span class="green">le pinko</span> <span class="blue">in</span>, <span class="green">le no suki</span> <span class="blue">in mi</span></td><td><span class="red">The person</span> <strong>that</strong> <span class="red">I</span> <span class="green">assessed</span> <span class="green">doesn&#39;t like</span> <span class="blue">me</span></td></tr></tbody></table><hr><h2 id="derivational-markers" tabindex="-1"><a class="header-anchor" href="#derivational-markers"><span>Derivational Markers</span></a></h2><p><a href="https://dictionary.kokanu.com/wi?lang=en" style="text-decoration:none;">wi</a> and <a href="https://dictionary.kokanu.com/mu?lang=en" style="text-decoration:none;">mu</a> are markers that apply to an arbitrary amount of words (often one, but can be more). <a href="https://dictionary.kokanu.com/wi?lang=en" style="text-decoration:none;">wi</a> forces words into <strong>modifiers</strong>, and is often used in the construction <a href="https://dictionary.kokanu.com/wi?lang=en" style="text-decoration:none;">wi</a> <a href="https://dictionary.kokanu.com/no?lang=en" style="text-decoration:none;">no</a> to negate adjectives, and to change the intensity of an adjective.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td>ɤıx̄ı <span class="yellow">xʃƨ̄ȷ</span></td><td>sikin <span class="yellow">konen</span></td><td>probable event</td></tr><tr><td>ɤıx̄ı <span class="green">ɕı</span> <span class="magenta">ƨʃ</span> <span class="yellow">xʃƨ̄ȷ</span></td><td>sikin <span class="green">wi</span> <span class="magenta">no</span> <span class="yellow">konen</span></td><td>improbable event</td></tr><tr><td>xſɕʃɤı <span class="yellow">ɞx̄</span></td><td>kuwosi <span class="yellow">makan</span></td><td>edible fruit</td></tr><tr><td>xſɕʃɤı <span class="green">ɕı</span> <span class="magenta">ƨʃ</span> <span class="yellow">ɞx̄</span></td><td>kuwosi <span class="green">wi</span> <span class="magenta">no</span> <span class="yellow">makan</span></td><td>inedible fruit</td></tr></tbody></table>`,26),i(`p`,null,[l[16]||=e(`For more information, see `,-1),a(h,{to:`/reference/special-words/wi.html`},{default:r(()=>[...l[15]||=[e(`the page on wi`,-1)]]),_:1}),l[17]||=e(`.`,-1)]),l[28]||=n(`<p><a href="https://dictionary.kokanu.com/mu?lang=en" style="text-decoration:none;">mu</a> constructs a noun that is a &quot;doer&quot; of an action, or the <strong>agent</strong> of the action.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td>ɞſ xƨıɤ</td><td>mu kanisa</td><td>thinker</td></tr></tbody></table><p>To make the <strong>agent</strong> <em>cause</em> the action rather than <em>do</em> the action, you can replace <a href="https://dictionary.kokanu.com/mu?lang=en" style="text-decoration:none;">mu</a> with <a href="https://dictionary.kokanu.com/pan?lang=en" style="text-decoration:none;">pan</a>.</p><table><thead><tr><th>Likanu</th><th>Latin script</th><th>English</th></tr></thead><tbody><tr><td>ɞſ ʌıxſ</td><td>mu tiku</td><td>dier</td></tr><tr><td>ʜ̄ ʌıxſ</td><td>pan tiku</td><td>killer</td></tr></tbody></table>`,4),i(`p`,null,[l[20]||=e(`For more information, see the `,-1),a(h,{to:`/reference/special-words/mu.html`},{default:r(()=>[...l[18]||=[e(`page on mu`,-1)]]),_:1}),l[21]||=e(` and the `,-1),a(h,{to:`/reference/special-words/pan.html`},{default:r(()=>[...l[19]||=[e(`page on pan`,-1)]]),_:1}),l[22]||=e(`.`,-1)])])}var p=c(u,[[`render`,f]]);export{l as _pageData,p as default};